"""Единая точка получения путей ядра (core-level): модель и фабрика от root."""from __future__ import annotationsimport osimport sysfrom dataclasses import dataclassfrom pathlib import Path# Корень репозитория: src/core/app_path.py -> project root_PROJECT_ROOT = Path(__file__).resolve().parents[2]def resolve_runtime_root(profile: str | None = None) -> Path:    """    Корень рабочей среды (runtime).    - Собранное приложение (frozen): каталог с exe — root, в нём создаются data/, logs/, projects/ и т.д.    - Запуск из исходников: project_root / runtime / <profile>, профиль из APP_PROFILE или "dev".    """    if getattr(sys, "frozen", False):        return Path(sys.executable).resolve().parent    _profile = profile if profile is not None else os.getenv("APP_PROFILE", "dev")    return _PROJECT_ROOT / "runtime" / _profiledef project_root() -> Path:    """Корень репозитория (project root)."""    return _PROJECT_ROOTdef _default_app_root() -> Path:    """Возвращает runtime root для boundary-слоя (bootstrap, fallback)."""    return resolve_runtime_root()@dataclass(frozen=True)class AppPath:    """Типизированные пути корня приложения и стандартных каталогов/файлов."""    root: Path    app_ini: Path    logs_dir: Path    system_log: Path    data_dir: Path    source_dir: Path    data_user_dir: Path    projects_dir: Path    cache_dir: Path    temp_dir: Path    @staticmethod    def from_root(root: Path | None = None) -> AppPath:        """Строит AppPath от корня приложения. По умолчанию (root=None) — resolve_runtime_root()."""        resolved = Path(root) if root is not None else _default_app_root()        return AppPath(            root=resolved,            app_ini=resolved / "app.ini",            logs_dir=resolved / "logs",            system_log=resolved / "logs" / "system.log",            data_dir=resolved / "data",            source_dir=resolved / "data" / "source",            data_user_dir=resolved / "data" / "user",            projects_dir=resolved / "projects",            cache_dir=resolved / "cache",            temp_dir=resolved / "temp",        )